    "questionnaire": "https://fhir.kemkes.go.id/Questionnaire/Q0042",
    "item": [
        {
            "linkId": "1",
            "text": "Penurunan Kognitif",
            "item": [
                {
                    "linkId": "1.1",
                    "text": "Orientasi waktu dan tempat: Tanggal berapakah hari ini secara lengkap (tanggal/bulan/tahun)? atau Dimanakah Anda saat ini (Puskesmas, rumah, klinik, dll)?",
                    "answer": [
                        {
                            "valueBoolean": true
                        }
                    ]
                },
                {
                    "linkId": "1.2",
                    "text": "Apakah peserta dapat mengingat tiga kata sebelumnya?",
                    "answer": [
                        {
                            "valueBoolean": false
                        }
                    ]
                }
            ]
        },
        {
            "linkId": "2",
            "text": "Keterbatasan Mobilisasi",
            "item": [
                {
                    "linkId": "2.1",
                    "text": "Tes Berdiri di kursi: Berdiri dari kursi lima kali tanpa bantuan tangan. Apakah orang tersebut dapat berdiri dari kursi utuh sebanyak lima kali dalam 14 detik?",
                    "answer": [
                        {
                            "valueBoolean": false
                        }
                    ]
                }
            ]
        },
        {
            "linkId": "3",
            "text": "Malnutrisi",
            "item": [
                {
                    "linkId": "3.1",
                    "text": "Apakah berat badan Anda berkurang >3 kg dalam 3 bulan terakhir atau pakaian menjadi lebih longgar?",
                    "answer": [
                        {
                            "valueBoolean": true
                        }
                    ]
                },
                {
                    "linkId": "3.2",
                    "text": "Apakah Anda hilang nafsu makan Atau mengalami kesulitan makan (misal batuk atau tersedak saat makan, menggunakan selang makan/sonde)?",
                    "answer": [
                        {
                            "valueBoolean": false
                        }
                    ]
                },
                {
                    "linkId": "3.3",
                    "text": "Apakah ukuran lingkar lengan atas (LiLA) <21 cm?",
                    "answer": [
                        {
                            "valueBoolean": true
                        }
                    ]
                }
            ]
        },
        {
            "linkId": "4",
            "text": "Gangguan Penglihatan",
            "item": [
                {
                    "linkId": "4.1",
                    "text": "Apakah Anda mengalami masalah pada mata: kesulitan melihat jauh, membaca, penyakit mata, atau sedang dalam pengobatan medis (diabetes, tekanan darah tinggi)?",
                    "answer": [
                        {
                            "valueBoolean": true
                        }
                    ]
                },
                {
                    "linkId": "4.2",
                    "text": "Tes Melihat : Apakah jawaban hitung jari benar dalam 3 kali berturut turut?",
                    "answer": [
                        {
                            "valueBoolean": true
                        }
                    ]
                }
            ]
        },
        {
            "linkId": "5",
            "text": "Gangguan Pendengaran",
            "item": [
                {
                    "linkId": "5.1",
                    "text": "Mendengar suara bisikan saat tes bisik?",
                    "answer": [
                        {
                            "valueBoolean": true
                        }
                    ]
                }
            ]
        },
        {
            "linkId": "6",
            "text": "Gejala Depresi",
            "item": [
                {
                    "linkId": "6.1",
                    "text": "Selama dua minggu terakhir, apakah Anda merasa terganggu oleh merasa sedih, tertekan, atau putus asa?",
                    "answer": [
                        {
                            "valueBoolean": false
                        }
                    ]
                },
                {
                    "linkId": "6.2",
                    "text": "Selama dua minggu terakhir, apakah Anda merasa terganggu oleh  sedikit minat atau kesenangan dalam melakukan sesuatu?",
                    "answer": [
                        {
                            "valueBoolean": true
                        }
                    ]
                }
            ]
        }
    ]
}

