            "linkId": "1",
            "text": "Apakah keluarga anda mengalami kesulitan dalam membuat keputusan? Misalnya tidak mampu memberi saran dengan benar, tidak mampu mengurus keuangan, membeli hadiah yang tidak layak untuk orang lain, bermasalah dengan pemikiran?",
            "answer": [
                {
                    "valueCoding": {
                        "system": "http://snomed.info/sct",
                        "code": "263703002",
                        "display": "Changed"
                    }
                }
            ]
        },
        {
            "linkId": "2",
            "text": "Apakah keluarga anda sudah tidak menekuni hobi/ kegiatan yang sebelumnya disenangi? Misalnya merajut, menjahit, berkebun, memasak kue, membaca buku, bermain catur, memainkan alat musik atau bernyanyi?",
            "answer": [
                {
                    "valueCoding": {
                        "system": "http://snomed.info/sct",
                        "code": "260388006",
                        "display": "Unchanged"
                    }
                }
            ]
        },
        {
            "linkId": "3",
            "text": "Apakah keluarga anda mengulang-ngulang pertanyaan, cerita atau pernyataan yang sama?",
            "answer": [
                {
                    "valueCoding": {
                        "system": "http://snomed.info/sct",
                        "code": "263703002",
                        "display": "Changed"
                    }
                }
            ]
        },
        {
            "linkId": "4",
            "text": "Apakah keluarga anda mengalami kesulitan belajar menggunakan perkakas dan peralatan? Seperti TV, radio, komputer, microwave, remote control, setrika, blender?",
            "answer": [
                {
                    "valueCoding": {
                        "system": "http://snomed.info/sct",
                        "code": "260388006",
                        "display": "Unchanged"
                    }
                }
            ]
        },
        {
            "linkId": "5",
            "text": "Apakah klien/pasien lansia lupa nama bulan atau tahun?",
            "answer": [
                {
                    "valueCoding": {
                        "system": "http://snomed.info/sct",
                        "code": "263703002",
                        "display": "Changed"
                    }
                }
            ]
        },
        {
            "linkId": "6",
            "text": "Apakah klien/pasien lansia mengalami kesulitan mengatur keuangan? Misalnya membayar rekening air/listrik, periksa buku cek, pajak pendapatan, mengambil yang pensiun di bank?",
            "answer": [
                {
                    "valueCoding": {
                        "system": "http://snomed.info/sct",
                        "code": "260388006",
                        "display": "Unchanged"
                    }
                }
            ]
        },
        {
            "linkId": "7",
            "text": "Apakah klien/pasien lansia mengalami kesulitan mengingat janji terhadap orang lain?",
            "answer": [
                {
                    "valueCoding": {
                        "system": "http://snomed.info/sct",
                        "code": "261665006",
                        "display": "Unknown"
                    }
                }
            ]
        },
        {
            "linkId": "8",
            "text": "Apakah klien/pasien lansia sehari-harinya mengalami gangguan memori dan pemikiran yang konsisten? Misalnya lupa meletakkan kaca mata, kunci kendaraan, meletakkan barang tidak sesuai pada tempatnya?",
            "answer": [
                {
                    "valueCoding": {
                        "system": "http://snomed.info/sct",
                        "code": "263703002",
                        "display": "Changed"
                    }
                }
            ]
        },
        {
            "linkId": "9",
            "text": "Total skor AD-8",
            "answer": [
                {
                    "valueReference": {
                        "reference": "Observation/{{Observation_AD8}}"
                    }
                }
            ]
        }
    ]
}

