    "item": [
        {
            "linkId": "1",
            "text": "Dengan usaha sendiri tanpa bantuan alat berjalan, apakah Anda mengalami kesulitan untuk naik 10 anak tangga dan tanpa istirahat diantaranya?",
            "answer": [
                {
                    "valueBoolean": true
                }
            ]
        },
        {
            "linkId": "2",
            "text": "Seberapa sering dalam 4 minggu anda merasa kelelahan?",
            "answer": [
                {
                    "valueCoding": {
                        "system": "http://snomed.info/sct",
                        "code": "267032009",
                        "display": "Tired all the time"
                    }
                }
            ]
        },
        {
            "linkId": "3",
            "text": "Penyakit lebih dari 5",
            "item": [
                {
                    "linkId": "3.1",
                    "text": "Apakah dokter pernah mengatakan kepada anda tentang penyakit anda?",
                    "answer": [
                        {
                            "valueCoding": {
                                "system": "http://terminology.kemkes.go.id",
                                "code": "TK000231",
                                "display": "Memiliki 0-4 penyakit"
                            }
                        }
                    ]
                },
                {
                    "linkId": "3.2",
                    "text": "Penyakit yang dimiliki",
                    "answer": [
                        {
                            "valueReference": {
                                "reference": "Condition/{{Condition_RiwayatPenyakitPribadiSekarang}}"
                            }
                        }
                    ]
                }
            ]
        },
        {
            "linkId": "4",
            "text": "Dengan usaha sendiri tanpa bantuan alat berjalan, apakah anda mengalami kesulitan berjalan kira-kira sejauh 100 sampai 200 meter?",
            "answer": [
                {
                    "valueBoolean": true
                }
            ]
        },
        {
            "linkId": "5",
            "text": "Hilangnya Berat Badan",
            "item": [
                {
                    "linkId": "5.1",
                    "text": "Berapa berat badan saudara dengan mengenakan baju tanpa alas kaki saat ini?",
                    "answer": [
                        {
                            "valueReference": {
                                "reference": "Observation/{{Observation_BB}}"
                            }
                        }
                    ]
                },
                {
                    "linkId": "5.2",
                    "text": "Satu tahun yang lalu, berapa berat badan anda dengan mengenakan baju tanpa alas kaki?",
                    "answer": [
                        {
                            "valueQuantity": {
                                "value": 40,
                                "system": "http://unitsofmeasure.org",
                                "code": "kg",
                                "unit": "kg"
                            }
                        }
                    ]
                },
                {
                    "linkId": "5.3",
                    "text": "Perhitungan berat badan dalam persen = berat badan 1 tahun yang lalu – berat badan sekarang)/ berat badan satu tahun lalu)] x 100 %",
                    "answer": [
                        {
                            "valueCoding": {
                                "system": "http://terminology.kemkes.go.id",
                                "code": "TK000234",
                                "display": "< 5%"
                            }
                        }
                    ]
                }
            ]
        },
        {
            "linkId": "6",
            "text": "Total Skor Skrining Kerentanan (RAPUH)",
            "answer": [
                {
                    "valueReference": {
                        "reference": "Observation/{{Observation_RAPUH}}"
                    }
                }
            ]
        }
    ]
}

